64	// Note that this in this setup is usually a descriptor constructed from a page,
65	// so we want to find the best match for that page.
66	func (s descriptorHandler) compareDescriptors(category Category, this, other TemplateDescriptor, sitesMatrixThis, sitesMatrixOther sitesmatrix.VectorProvider) weight {
67		if this.LayoutFromUserMustMatch && this.LayoutFromUser != other.LayoutFromTemplate {
68			return weightNoMatch
69		}
70	
71		w := this.doCompare(category, other, sitesMatrixThis, sitesMatrixOther)
72	
73		if w.w1 <= 0 {
74			if sitesMatrixOther != nil {
75				if sitesMatrixThis == nil || !sitesMatrixOther.HasAnyVector(sitesMatrixThis) {
76					return w
77				}
78			}
79	
80			if category == CategoryMarkup && (this.Variant1 == other.Variant1) && (this.Variant2 == other.Variant2 || this.Variant2 != "" && other.Variant2 == "") {
81				// See issue 13242.
82				if this.OutputFormat != other.OutputFormat && this.OutputFormat == s.opts.DefaultOutputFormat {
83					return w
84				}
85	
86				w.w1 = 1
87			}
88	
89			if category == CategoryShortcode {
90				if (this.IsPlainText == other.IsPlainText || !other.IsPlainText) || this.AlwaysAllowPlainText {
91					w.w1 = 1
92				}
93			}
94		}
95	
96		return w
97	}
